package com.rehealth.genie.features

import com.rehealth.genie.ring.RingMetricType
import com.rehealth.genie.ring.data.RingActivityEntity
import com.rehealth.genie.ring.data.RingMeasurementEntity
import kotlin.math.round

class HealthFeatureExtractor(
    private val nowProvider: () -> Long = { System.currentTimeMillis() },
) {
    fun extract(
        profile: ProfileFeatureInput,
        measurements: List<RingMeasurementEntity>,
        activities: List<RingActivityEntity>,
    ): HealthFeatureExtractionResult {
        val generatedAt = nowProvider()
        val quality = linkedMapOf<String, FeatureQuality>()
        val missing = mutableListOf<String>()

        val age = required(
            name = CvdFeatureNames.AGE,
            value = profile.age?.takeIf { it in 18..100 },
            quality = FeatureQuality.USER_REPORTED,
            qualityMap = quality,
            missing = missing,
        )
        val gender = required(
            name = CvdFeatureNames.GENDER,
            value = profile.gender?.modelValue,
            quality = FeatureQuality.USER_REPORTED,
            qualityMap = quality,
            missing = missing,
        )
        val bmi = required(
            name = CvdFeatureNames.BMI,
            value = profile.bmi?.takeIf { it in 15.0..60.0 }
                ?: deriveBmi(profile.heightCm, profile.weightKg),
            quality = if (profile.bmi != null) FeatureQuality.USER_REPORTED else FeatureQuality.DERIVED,
            qualityMap = quality,
            missing = missing,
        )

        val bloodPressure = latestMeasurement(measurements, RingMetricType.BLOOD_PRESSURE)
        val bpQuality = bloodPressure?.qualityFor(generatedAt, STALE_BLOOD_PRESSURE_MS)
        val sbp = required(
            name = CvdFeatureNames.SBP,
            value = bloodPressure?.primaryValue?.takeIf { it in 60.0..250.0 },
            quality = bpQuality ?: FeatureQuality.MISSING,
            qualityMap = quality,
            missing = missing,
        )
        val dbp = required(
            name = CvdFeatureNames.DBP,
            value = bloodPressure?.secondaryValue?.takeIf { it in 40.0..150.0 },
            quality = bpQuality ?: FeatureQuality.MISSING,
            qualityMap = quality,
            missing = missing,
        )

        val exerciseDays = estimateExerciseDays(activities, generatedAt)
        if (exerciseDays == null) {
            quality[CvdFeatureNames.EXERCISE_DAYS] = FeatureQuality.MISSING
            missing += CvdFeatureNames.EXERCISE_DAYS
        } else {
            quality[CvdFeatureNames.EXERCISE_DAYS] = FeatureQuality.DERIVED
        }

        val smoking = requiredFlag(CvdFeatureNames.SMOKING, profile.smoking, quality, missing)
        val drinking = requiredFlag(CvdFeatureNames.DRINKING, profile.drinking, quality, missing)
        val diabetesHistory = requiredFlag(CvdFeatureNames.DIABETES_HISTORY, profile.diabetesHistory, quality, missing)
        val hypertensionHistory = requiredFlag(CvdFeatureNames.HYPERTENSION_HISTORY, profile.hypertensionHistory, quality, missing)
        val familyHistory = requiredFlag(CvdFeatureNames.FAMILY_HISTORY, profile.familyHistory, quality, missing)

        val fastingGlucose = optionalClinical(
            CvdFeatureNames.FASTING_GLUCOSE,
            profile.fastingGlucose?.takeIf { it in 2.0..35.0 },
            quality,
        )
        val totalCholesterol = optionalClinical(
            CvdFeatureNames.TOTAL_CHOLESTEROL,
            profile.totalCholesterol?.takeIf { it in 2.0..20.0 },
            quality,
        )
        val ldl = optionalClinical(CvdFeatureNames.LDL, profile.ldl?.takeIf { it in 0.5..10.0 }, quality)
        val hdl = optionalClinical(CvdFeatureNames.HDL, profile.hdl?.takeIf { it in 0.3..5.0 }, quality)
        val triglycerides = optionalClinical(
            CvdFeatureNames.TRIGLYCERIDES,
            profile.triglycerides?.takeIf { it in 0.2..20.0 },
            quality,
        )

        val vector = if (missing.isEmpty()) {
            CvdFeatureVector(
                age = age!!,
                gender = gender!!,
                bmi = bmi!!,
                sbp = sbp!!,
                dbp = dbp!!,
                fastingGlucose = fastingGlucose,
                totalCholesterol = totalCholesterol,
                ldl = ldl,
                hdl = hdl,
                triglycerides = triglycerides,
                exerciseDays = exerciseDays!!,
                smoking = smoking!!,
                drinking = drinking!!,
                diabetesHistory = diabetesHistory!!,
                hypertensionHistory = hypertensionHistory!!,
                familyHistory = familyHistory!!,
                featureQuality = quality.toMap(),
            )
        } else {
            null
        }

        return HealthFeatureExtractionResult(
            vector = vector,
            missingRequiredFields = missing.distinct(),
            generatedAt = generatedAt,
            featureQuality = quality.toMap(),
        )
    }

    private fun <T> required(
        name: String,
        value: T?,
        quality: FeatureQuality,
        qualityMap: MutableMap<String, FeatureQuality>,
        missing: MutableList<String>,
    ): T? {
        qualityMap[name] = if (value == null) FeatureQuality.MISSING else quality
        if (value == null) missing += name
        return value
    }

    private fun requiredFlag(
        name: String,
        value: Boolean?,
        quality: MutableMap<String, FeatureQuality>,
        missing: MutableList<String>,
    ): Int? = required(
        name = name,
        value = value?.toModelFlag(),
        quality = FeatureQuality.USER_REPORTED,
        qualityMap = quality,
        missing = missing,
    )

    private fun optionalClinical(
        name: String,
        value: Double?,
        quality: MutableMap<String, FeatureQuality>,
    ): Double? {
        quality[name] = if (value == null) FeatureQuality.MISSING else FeatureQuality.CLINICAL_REPORT
        return value
    }

    private fun latestMeasurement(
        measurements: List<RingMeasurementEntity>,
        type: RingMetricType,
    ): RingMeasurementEntity? =
        measurements
            .filter { it.metricType == type.name }
            .maxByOrNull { it.measuredAt }

    private fun estimateExerciseDays(
        activities: List<RingActivityEntity>,
        now: Long,
    ): Int? {
        val recent = activities.filter { it.startedAt in (now - EXERCISE_WINDOW_MS)..now }
        if (recent.isEmpty()) return null
        return recent
            .groupBy { it.startedAt / DAY_MS }
            .count { (_, dayActivities) -> dayActivities.sumOf { it.steps } >= ACTIVE_DAY_STEPS }
            .coerceIn(0, 7)
    }

    private fun RingMeasurementEntity.qualityFor(now: Long, staleAfterMs: Long): FeatureQuality =
        if (measuredAt < now - staleAfterMs) FeatureQuality.STALE else FeatureQuality.REAL_DEVICE

    private fun deriveBmi(heightCm: Double?, weightKg: Double?): Double? {
        if (heightCm == null || weightKg == null || heightCm <= 0.0 || weightKg <= 0.0) return null
        val meters = heightCm / 100.0
        val bmi = weightKg / (meters * meters)
        return round(bmi * 10.0) / 10.0
    }

    private fun Boolean.toModelFlag(): Int = if (this) 1 else 0

    private companion object {
        const val DAY_MS = 24 * 60 * 60 * 1000L
        const val EXERCISE_WINDOW_MS = 7 * DAY_MS
        const val STALE_BLOOD_PRESSURE_MS = 30 * DAY_MS
        const val ACTIVE_DAY_STEPS = 6_000
    }
}

