    @IgnoreAuth
    @PostMapping("/ring/snapshots")
    @Operation(summary = "涓婁紶鏅鸿兘鎴掓寚鍋ュ悍蹇収")
    public Result<Map<String, Object>> uploadRingSnapshot(@RequestBody RingSnapshotRequest request) {
        String snapshotId = UUID.randomUUID().toString();
        long receivedAt = System.currentTimeMillis();
        AlgorithmResult risk = predictRisk(request);
        StoredSnapshot snapshot = new StoredSnapshot();
        snapshot.snapshotId = snapshotId;
        snapshot.receivedAt = receivedAt;
        snapshot.request = request;
