        record.itemId = request.itemId;
        record.status = request.status == null ? "done" : request.status;
        record.mood = request.mood == null ? "stable" : request.mood;
        record.note = request.note;
        record.checkedAt = request.checkedAt == null ? System.currentTimeMillis() : request.checkedAt;
