    private AlgorithmResult predictRisk(RingSnapshotRequest request) {
        if (hasAlgorithmService()) {
            try {
                return callAlgorithmService(request);
            } catch (Exception ignored) {
                return mockRisk(request, "mock_fallback");
            }
        }
        return mockRisk(request, "mock");
    }

    private AlgorithmResult callAlgorithmService(RingSnapshotRequest request) throws IOException, InterruptedException {
        JSONObject payload = new JSONObject();
        payload.put("age", PROFILE.age == null ? 45 : PROFILE.age);
        payload.put("gender", PROFILE.gender == null ? "unknown" : PROFILE.gender);
        payload.put("bmi", PROFILE.bmi == null ? 23.5 : PROFILE.bmi);
        payload.put("sbp", measurementValue(request, "BLOOD_PRESSURE", 118.0));
        payload.put("dbp", measurementSecondaryValue(request, "BLOOD_PRESSURE", 76.0));
        payload.put("fasting_glucose", 5.2);
        payload.put("total_cholesterol", 4.8);
        payload.put("ldl", 2.7);
        payload.put("hdl", 1.3);
        payload.put("triglycerides", 1.4);
        payload.put("exercise_days", estimateExerciseDays(request));
        payload.put("smoking", booleanFlag(PROFILE.smoking));
        payload.put("drinking", booleanFlag(PROFILE.drinking));
        payload.put("diabetes_history", booleanFlag(PROFILE.diabetesHistory));
        payload.put("hypertension_history", booleanFlag(PROFILE.hypertensionHistory));
        payload.put("family_history", booleanFlag(PROFILE.familyHistory));

        String url = algorithmBaseUrl.replaceAll("/+$", "") + "/api/pias/predict";
        HttpRequest httpRequest = HttpRequest.newBuilder(URI.create(url))
                .header("Content-Type", "application/json")
                .POST(HttpRequest.BodyPublishers.ofString(payload.toJSONString()))
                .build();
        HttpResponse<String> response = httpClient.send(httpRequest, HttpResponse.BodyHandlers.ofString());
        if (response.statusCode() < 200 || response.statusCode() >= 300) {
            throw new IOException("Algorithm service returned " + response.statusCode());
        }
        JSONObject body = JSON.parseObject(response.body());
        AlgorithmResult result = new AlgorithmResult();
        result.mode = "http";
        result.modelVersion = body.getString("model_version");
        result.riskScore = body.getDoubleValue("risk_score");
        result.riskLevel = body.getString("risk_level");
        result.summary = "PIAS model prediction";
        result.generatedAt = Instant.now().toString();
        result.contributions = body.get("feature_contributions");
        return result;
    }

    private AlgorithmResult mockRisk(RingSnapshotRequest request, String mode) {
        double hr = measurementValue(request, "HEART_RATE", 72.0);
