        double sbp = measurementValue(request, "BLOOD_PRESSURE", 118.0);
        double stress = measurementValue(request, "STRESS", 35.0);
        int sleepMinutes = request.sleep == null ? 420 :
                request.sleep.deepMinutes + request.sleep.lightMinutes + request.sleep.awakeMinutes + request.sleep.remMinutes;

        double score = 0.18;
        if (hr > 85) {
            score += 0.08;
        }
        if (spo2 < 95) {
            score += 0.10;
        }
        if (sbp > 130) {
            score += 0.12;
        }
        if (stress > 55) {
            score += 0.08;
        }
        if (sleepMinutes < 360) {
            score += 0.07;
        }
        if (Boolean.TRUE.equals(PROFILE.hypertensionHistory)) {
            score += 0.08;
        }
        if (Boolean.TRUE.equals(PROFILE.diabetesHistory)) {
            score += 0.08;
        }
        if (Boolean.TRUE.equals(PROFILE.familyHistory)) {
            score += 0.04;
        }
        if (Boolean.TRUE.equals(PROFILE.smoking)) {
            score += 0.05;
        }
        if (PROFILE.bmi != null && PROFILE.bmi >= 28) {
            score += 0.06;
        }
        score = Math.max(0.02, Math.min(0.85, score));

        AlgorithmResult result = new AlgorithmResult();
        result.mode = mode;
        result.modelVersion = "rehealth-mobile-mock-0.1";
        result.riskScore = Math.round(score * 1000.0) / 1000.0;
        result.riskLevel = score >= 0.45 ? "high" : score >= 0.28 ? "medium" : "low";
        result.summary = "鍩轰簬鎴掓寚蹇収鐨勬湰鍦拌仈璋冮闄╂憳瑕侊紝涓嶄唬琛ㄥ尰瀛﹁瘖鏂?;
        result.generatedAt = Instant.now().toString();
        Map<String, Object> contributions = new LinkedHashMap<>();
        contributions.put("heart_rate", hr);
        contributions.put("blood_oxygen", spo2);
        contributions.put("systolic_bp", sbp);
        contributions.put("stress", stress);
        contributions.put("sleep_minutes", sleepMinutes);
        contributions.put("profile_bmi", PROFILE.bmi);
        contributions.put("hypertension_history", PROFILE.hypertensionHistory);
        contributions.put("diabetes_history", PROFILE.diabetesHistory);
        result.contributions = contributions;
        return result;
    }

    private Map<String, Object> buildPatientMvp() {
        AlgorithmResult risk = currentRisk();
        Map<String, Object> data = new LinkedHashMap<>();
        data.put("profile", PROFILE);
        data.put("risk", risk);
        data.put("interventionPlan", buildInterventionPlan(risk));
        synchronized (CHECK_INS) {
            data.put("recentCheckins", new ArrayList<>(CHECK_INS));
        }
        data.put("updatedAt", System.currentTimeMillis());
        return data;
    }

