    private boolean hasAlgorithmService() {
        return algorithmBaseUrl != null && !algorithmBaseUrl.isBlank();
    }

    private double measurementValue(RingSnapshotRequest request, String metricType, double fallback) {
        if (request.measurements == null) {
            return fallback;
        }
        return request.measurements.stream()
                .filter(item -> metricType.equals(item.metricType))
                .map(item -> item.primaryValue)
                .filter(value -> value != null)
                .findFirst()
                .orElse(fallback);
    }

    private double measurementSecondaryValue(RingSnapshotRequest request, String metricType, double fallback) {
        if (request.measurements == null) {
            return fallback;
        }
        return request.measurements.stream()
                .filter(item -> metricType.equals(item.metricType))
                .map(item -> item.secondaryValue)
                .filter(value -> value != null)
                .findFirst()
                .orElse(fallback);
    }

    private int estimateExerciseDays(RingSnapshotRequest request) {
        double steps = measurementValue(request, "STEPS", 6000.0);
        return steps >= 8000 ? 5 : steps >= 5000 ? 3 : 1;
    }

    private int booleanFlag(Boolean value) {
        return Boolean.TRUE.equals(value) ? 1 : 0;
    }

